<template><div class="rounded-xl border border-gray-200 p-4 dark:border-dark-700"><div class="flex items-center justify-between"><div><h3 class="text-sm font-semibold">{{ t('admin.settings.features.webChat.documents') }}</h3><p class="text-xs text-gray-500">{{ t('admin.settings.features.webChat.documentsHint') }}</p></div><Toggle v-model="form.enabled"/></div><div class="mt-4 grid gap-3 md:grid-cols-3"><label class="field">{{ t('webChat.maxFileMB') }}<input v-model.number="maxFileMB" type="number" class="input" min="1"/></label><label class="field">{{ t('webChat.maxProjectFiles') }}<input v-model.number="form.limits.max_files_per_project" type="number" class="input" min="1"/></label><label class="field">{{ t('webChat.maxUserMB') }}<input v-model.number="maxUserMB" type="number" class="input" min="1"/></label></div><div class="mt-4 grid gap-3 md:grid-cols-2"><label class="field">Endpoint<input v-model="form.s3.endpoint" class="input"/></label><label class="field">Region<input v-model="form.s3.region" class="input" placeholder="auto"/></label><label class="field">Bucket<input v-model="form.s3.bucket" class="input"/></label><label class="field">Access Key ID<input v-model="form.s3.access_key_id" class="input"/></label><label class="field">Secret Access Key<input v-model="form.s3.secret_access_key" type="password" class="input" :placeholder="t('webChat.keepExistingSecret')"/></label><label class="field">Prefix<input v-model="form.s3.prefix" class="input" placeholder="web-chat/"/></label></div><label class="mt-3 block text-xs"><input v-model="form.s3.force_path_style" type="checkbox"/> Force path style</label><p v-if="message" class="mt-3 text-sm" :class="error?'text-red-500':'text-green-600'">{{ message }}</p><div class="mt-4 flex justify-end gap-2"><button class="btn btn-secondary" :disabled="busy" @click="test">{{ t('common.test') }}</button><button class="btn btn-primary" :disabled="busy" @click="save">{{ t('common.save') }}</button></div></div></template>
<script setup lang="ts">import{computed,onMounted,reactive,ref}from'vue';import{useI18n}from'vue-i18n';import Toggle from '@/components/common/Toggle.vue';import webChatAPI,{type WebChatDocumentAdminConfig}from'@/api/webChat';import{extractApiErrorMessage}from'@/utils/apiError';const{t}=useI18n();const busy=ref(false),message=ref(''),error=ref(false);const form=reactive<WebChatDocumentAdminConfig>({enabled:false,limits:{max_file_bytes:20*1024*1024,max_files_per_project:50,max_bytes_per_user:500*1024*1024},s3:{endpoint:'',region:'auto',bucket:'',access_key_id:'',secret_access_key:'',prefix:'web-chat/',force_path_style:false}});const maxFileMB=computed({get:()=>Math.round(form.limits.max_file_bytes/1024/1024),set:v=>form.limits.max_file_bytes=Math.max(1,v||1)*1024*1024});const maxUserMB=computed({get:()=>Math.round(form.limits.max_bytes_per_user/1024/1024),set:v=>form.limits.max_bytes_per_user=Math.max(1,v||1)*1024*1024});onMounted(async()=>Object.assign(form,await webChatAPI.adminGetDocumentConfig()));async function run(fn:()=>Promise<unknown>,ok:string){busy.value=true;message.value='';try{await fn();error.value=false;message.value=ok}catch(e){error.value=true;message.value=extractApiErrorMessage(e)}finally{busy.value=false}}async function test(){await run(()=>webChatAPI.adminTestDocumentS3({...form.s3}),t('webChat.s3TestSuccess'))}async function save(){await run(async()=>Object.assign(form,await webChatAPI.adminUpdateDocumentConfig({...form,limits:{...form.limits},s3:{...form.s3}})),t('common.saved'))}</script><style scoped>.field{display:flex;flex-direction:column;gap:.3rem;font-size:.75rem;font-weight:700;color:#64748b}</style>
